dynamicCss:
        body.notion-body {
    background-color: '${fallbackColor}';
    background-image: url('${imageUrl}') !important;
    background-size: cover !important;
    background-position: center center !important;
    background-repeat: no-repeat !important;
    background-attachment: fixed !important;
}

body.notion-body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background-color: '${overlayColor}';
    z-index: -1;
}

.notion-frame,
/* .notion-scroller, */
.notion-cursor-listener,
.notion-app-inner,
.notion-table-view-header-row,
.notion-cursor-listener header,
.notion-collection_view_page-block .pseudoSelection,
.notion-table-view-add-row:not(:hover),
.notion-peek-renderer,
.notion-page-content,
div[role="menu"]>div {
    background: transparent !important;
}

.notion-light-theme h1,
.notion-light-theme h2,
.notion-light-theme h3 {
    text-shadow: 0px 0px 5px rgba(0, 0, 0, 0.4);
}

div:has(> div > .notion-table-view-header-row) {
    background: transparent !important;
    backdrop-filter: blur(10px);
}

.notion-dark-theme .notion-table-block td,
.notion-dark-theme .notion-table-block th {
    border: 1px solid rgba(255, 255, 255, 0.2) !important;
}

.notion-light-theme .notion-table-block td,
.notion-light-theme .notion-table-block th {
    border: 1px solid rgba(0, 0, 0, 0.2) !important;
}

.notion-board-view div[style*="z-index: 85"],
.notion-board-view div[style*="z-index: 85"]>div:first-child {
    background: transparent !important;
}

.notion-light-theme {
    --c-icoDis: rgba(0, 0, 0, 0.6) !important; /* Cambia il carattere slash in alto a sinistra quando siamo su pagine figlie */
    --c-texTer: rgba(0, 0, 0, 0.6) !important; /* Cambia ad esempio il colore del testo "Write, press space for AI, / for commands..." */
    --cl-pagTitPlaTexCol: rgba(0, 0, 0, 0.6) !important; /* Ad es. Quando crei nuovo Inline Database, cambia il colore del testo "New database" */
    /* As of 2025-12-09, there's no need to override --c-graTexSec variable for light theme */
}
.notion-dark-theme {
    --c-icoDis: rgba(255, 255, 255, 0.6) !important; /* Cambia il carattere slash in alto a sinistra quando siamo su pagine figlie */
    --c-texTer: rgba(255, 255, 255, 0.6) !important; /* Cambia ad esempio il colore del testo "Write, press space for AI, / for commands..." */
    --cl-pagTitPlaTexCol: rgba(255, 255, 255, 0.6) !important; /* Ad es. Quando crei nuovo Inline Database, cambia il colore del testo "New database" */
    --c-graTexSec: rgba(255, 255, 255, 0.6) !important;
}

/* START - Scroll Bar */
.notion-light-theme * {
    scrollbar-color: rgba(0, 0, 0, 0.4) rgba(0, 0, 0, 0) !important;
}
/* As of 2025-12-09, there's no need to put this rule for dark theme */
/* END - Scroll Bar */

/* START - Code Block */
.notion-light-theme .notion-code-block {
    --ca-graBacPriTra: rgba(0, 0, 0, 0.1) !important; /* Background color */

    .operator {
        background: none !important;
    }
}
/* As of 2025-12-09, there's no need to put this rule for dark theme */
/* END - Code Block */

/* START - Table View */
.notion-light-theme .notion-table-view-header-row {
    --c-bacPri: rgba(0, 0, 0, 0.35) !important; /* Ad es. Sui database, a sinistra delle proprietà, appare un piccolo bordo */
}
.notion-dark-theme .notion-table-view-header-row {
    --c-bacPri: rgba(255, 255, 255, 0.35) !important; /* Ad es. Sui database, a sinistra delle proprietà, appare un piccolo bordo */
}
/* END - Table View */

/* START - Gallery View */
.notion-light-theme .notion-gallery-view {
    --cd-colGalPreCarBac: rgba(255, 255, 255, 0.4) !important; /* Ad es. Sui database, a sinistra delle proprietà, appare un piccolo bordo */
}
/* As of 2025-12-09, there's no need to put this rule for dark theme */
/* END - Gallery View */

/* START - Board View */
.notion-light-theme .notion-board-view {
    --c-bacPri: rgba(0, 0, 0, 0.35) !important; /* Sulle Board View, a sinistra appare un piccolo bordo */

    .notion-page-block a:not(:hover) {
        background: rgba(255, 255, 255, 0.5) !important; /* Colore di sfondo degli elementi nella board view*/
    }
    /* No need for .notion-board-group here*/
} 
.notion-dark-theme .notion-board-view  {
    --c-bacPri: rgba(255, 255, 255, 0.35) !important; /* Sulle Board View, a sinistra appare un piccolo bordo */

    .notion-board-group {
        backdrop-filter: blur(6px);
    }
    /* No need for .notion-page-block here*/
}
/* END - Board View */

/* START - Feed View -
Non è presente una classe di riferimento per Feed View, meglio evitare

.notion-light-theme .notion-page-block {
    --c-bacPri: rgba(255, 255, 255, 0.35) !important; Background elementi
}
.notion-dark-theme .notion-page-block {
    --c-bacSec: rgba(0, 0, 0, 0.35) !important; Background elementi
}
END - Feed View */

/* START - Calendar View */
.notion-light-theme .notion-calendar-view { 
    --c-bacPri: rgba(255, 255, 255, 0.6) !important; 
    --c-bacSec: rgba(255, 255, 255, 0.4) !important;
    --c-tabDivCol: rgba(255, 255, 255, 0.25) !important;
}
.notion-dark-theme .notion-calendar-view { 
    --c-bacPri: rgba(0, 0, 0, 0.6) !important; 
    --c-bacSec: rgba(0, 0, 0, 0.4) !important;
    --c-tabDivCol: rgba(0, 0, 0, 0.25) !important;
}
/* END - Calendar View */

/* START - Table of contents */
.notion-light-theme .notion-table_of_contents-block { 
    --c-graTexSec: rgba(0, 0, 0, 0.6) !important;
}
.notion-dark-theme .notion-table_of_contents-block { 
    --c-graTexSec: rgba(255, 255, 255, 0.6) !important;
}
/* END - Table of contents */
